//! Integration tests for `operations::get`.
//!
//! Each test stages and tears down its own data via `iput` / `imkdir`,
//! then drives `get_one` (or `get_one_annotated`) against the live
//! server. Drop guards run regardless of assertion outcome so the
//! tests stay idempotent.

use std::path::PathBuf;
use std::process::Command;


use baton_rs::operations::get::{get_one, get_one_annotated, GetOptions};
use baton_rs::types::{Collection, DataObject};
use baton_rs::{RodsConnection, Target};

/// Drop guard: `irm -r -f` removes data objects and populated
/// collections alike. Errors are swallowed because a test that fails
/// before staging may have nothing to clean up.
struct IrodsCleanup(String);
impl Drop for IrodsCleanup {
    fn drop(&mut self) {
        let _ = Command::new("irm").args(["-r", "-f", &self.0]).status();
    }
}

/// Drop guard for a local file written by `--save` mode tests. Errors
/// are swallowed — the file may not exist if the test panicked before
/// the save completed.
struct LocalCleanup(PathBuf);
impl Drop for LocalCleanup {
    fn drop(&mut self) {
        let _ = std::fs::remove_file(&self.0);
    }
}

fn iput(local: &str, remote: &str) {
    let status = Command::new("iput")
        .args(["-f", local, remote])
        .status()
        .expect("failed to spawn iput");
    assert!(status.success(), "iput {} {} failed", local, remote);
}

#[test]
fn get_inline_round_trips_data_object_bytes() {
    // Inline mode emits raw UTF-8 text (per upstream `read.c:116-135`
    // and #57 Cluster D). Use a payload exercising both ASCII and
    // multi-byte UTF-8 (CJK + emoji) so any encoding-layer bug —
    // codepoint truncation, replacement-character substitution, or
    // serde-string-vs-bytes confusion — shows up.
    let local = "/tmp/baton_rs_get_inline";
    let content = "ASCII baseline | café | 日本語 | 🦀";
    std::fs::write(local, content).expect("write");

    let remote_coll = "/testZone/home/irods";
    let data_object = "baton_rs_get_inline";
    let remote = format!("{}/{}", remote_coll, data_object);
    iput(local, &remote);
    let _cleanup = IrodsCleanup(remote.clone());

    let mut conn = RodsConnection::connect_from_env().expect("connect_from_env");
    conn.login_from_auth_file().expect("login_from_auth_file");

    let input = Target::DataObject(DataObject {
        collection: remote_coll.to_string(),
        data_object: data_object.to_string(),
        size: None,
        checksum: None,
        data: None,
        directory: None,
        file: None,
        avus: None,
        access: None,
        replicates: None,
        timestamps: None,
        error: None,
    });

    let output = get_one(&mut conn, input, &GetOptions::default()).expect("get_one");

    let d = match output {
        Target::DataObject(d) => d,
        other => panic!("expected DataObject on output, got {:?}", other),
    };
    let got = d.data.as_deref().expect("data field populated");

    assert_eq!(
        got, content,
        "byte-for-byte mismatch between iput input and get_one output"
    );
}

#[test]
fn get_inline_rejects_non_utf8_data_object() {
    // Mirror upstream `read.c:131-135` — non-UTF-8 bytes must surface
    // as USER_INPUT_PATH_ERR (-317000), not get silently base64'd or
    // string-lossy'd. partisan and extendo consume `data` as raw
    // text, so a non-UTF-8 emit would corrupt downstream parsers.
    let local = "/tmp/baton_rs_get_inline_nonutf8";
    // Lone 0xFF bytes — never valid UTF-8.
    let content: Vec<u8> = vec![0xFF, 0xFE, 0xFD];
    std::fs::write(local, &content).expect("write");

    let remote_coll = "/testZone/home/irods";
    let data_object = "baton_rs_get_inline_nonutf8";
    let remote = format!("{}/{}", remote_coll, data_object);
    iput(local, &remote);
    let _cleanup = IrodsCleanup(remote.clone());

    let mut conn = RodsConnection::connect_from_env().expect("connect_from_env");
    conn.login_from_auth_file().expect("login_from_auth_file");

    let input = Target::DataObject(DataObject {
        collection: remote_coll.to_string(),
        data_object: data_object.to_string(),
        size: None,
        checksum: None,
        data: None,
        directory: None,
        file: None,
        avus: None,
        access: None,
        replicates: None,
        timestamps: None,
        error: None,
    });

    let result = get_one(&mut conn, input, &GetOptions::default());
    let err = result.expect_err(
        "non-UTF-8 inline get must error rather than silently corrupt downstream"
    );
    assert_eq!(
        err.code, -317000,
        "expected USER_INPUT_PATH_ERR (-317000), got code {}: {}",
        err.code, err.message
    );
    assert!(
        err.message.contains("UTF-8"),
        "error message should mention UTF-8: {:?}",
        err.message
    );
}

