#[test]
fn get_inline_round_trips_multi_chunk_data_object() {
    // Larger than the 64 KiB read chunk so the read loop iterates more
    // than once. Use a deterministic ASCII pattern (valid UTF-8 since
    // ASCII is a UTF-8 subset) so the byte-equality check after the
    // read is meaningful and any sizing / chunk-boundary bug shows up.
    let local = "/tmp/baton_rs_get_multi_chunk";
    // 200 KiB of cycling printable ASCII (0x20..=0x7E, 95 codepoints).
    let pattern: String = (b' '..=b'~')
        .cycle()
        .take(200 * 1024)
        .map(|b| b as char)
        .collect();
    std::fs::write(local, &pattern).expect("write");

    let remote_coll = "/testZone/home/irods";
    let data_object = "baton_rs_get_multi_chunk";
    let remote = format!("{}/{}", remote_coll, data_object);
    iput(local, &remote);
    let _cleanup = IrodsCleanup(remote.clone());

    let mut conn = RodsConnection::connect_from_env().expect("connect_from_env");
    conn.login_from_auth_file().expect("login_from_auth_file");

    let input = Target::DataObject(DataObject {
        collection: remote_coll.to_string(),
        data_object: data_object.to_string(),
        size: None,
        checksum: None,
        data: None,
        directory: None,
        file: None,
        avus: None,
        access: None,
        replicates: None,
        timestamps: None,
        error: None,
    });

    let output = get_one(&mut conn, input, &GetOptions::default()).expect("get_one");
    let d = match output {
        Target::DataObject(d) => d,
        other => panic!("expected DataObject, got {:?}", other),
    };
    let got = d.data.as_deref().expect("data field populated");
    assert_eq!(got.len(), pattern.len(), "length mismatch");
    assert_eq!(got, pattern, "byte-for-byte mismatch across chunks");
}

#[test]
fn get_inline_round_trips_thirty_megabyte_data_object() {
    // Stress the read loop with a payload many hundreds of chunks
    // long. Catches off-by-one bugs in the chunk-length accounting
    // and any silent truncation iRODS might apply at internal page
    // boundaries. ~90 MB of transient local storage is expected:
    // local file (30 MB) + iRODS replica (30 MB) + in-memory String
    // (30 MB).
    //
    // Uses a cyclic ASCII pattern (valid UTF-8) so the exact-
    // equality assertion is deterministic across runs and any
    // divergence is reproducible.
    let local = "/tmp/baton_rs_get_30mb";
    const PAYLOAD_LEN: usize = 30 * 1024 * 1024;
    let pattern: String = (b' '..=b'~')
        .cycle()
        .take(PAYLOAD_LEN)
        .map(|b| b as char)
        .collect();
    std::fs::write(local, &pattern).expect("write");

    let remote_coll = "/testZone/home/irods";
    let data_object = "baton_rs_get_30mb";
    let remote = format!("{}/{}", remote_coll, data_object);
    iput(local, &remote);
    let _cleanup = IrodsCleanup(remote.clone());

    let mut conn = RodsConnection::connect_from_env().expect("connect_from_env");
    conn.login_from_auth_file().expect("login_from_auth_file");

    let input = Target::DataObject(DataObject {
        collection: remote_coll.to_string(),
        data_object: data_object.to_string(),
        size: None,
        checksum: None,
        data: None,
        directory: None,
        file: None,
        avus: None,
        access: None,
        replicates: None,
        timestamps: None,
        error: None,
    });

    let output = get_one(&mut conn, input, &GetOptions::default()).expect("get_one");
    let d = match output {
        Target::DataObject(d) => d,
        other => panic!("expected DataObject, got {:?}", other),
    };
    let got = d.data.as_deref().expect("data field populated");

    // assert_eq! on 30 MB Strings would dump the whole buffer to the
    // test log on mismatch — useless and slow. Length first, then a
    // bool comparison with a position-of-first-difference hint.
    assert_eq!(got.len(), pattern.len(), "length mismatch");
    if got != pattern {
        let pos = got
            .as_bytes()
            .iter()
            .zip(pattern.as_bytes().iter())
            .position(|(a, b)| a != b)
            .unwrap_or(0);
        let end = (pos + 16).min(got.len());
        panic!(
            "byte mismatch in 30 MB round-trip; first divergence at offset {pos}: \
             got={:02x?} expected={:02x?}",
            &got.as_bytes()[pos..end],
            &pattern.as_bytes()[pos..end],
        );
    }

    // Free the local copy ASAP — the in-memory pattern + got
    // buffers still occupy ~60 MB until the function returns.
    let _ = std::fs::remove_file(local);
}

